// ---- ENRICH + NORMALIZE ----
// Sources are messy and inconsistent (Zillow ADF vs Facebook form vs IDX widget).
// Standardize everything so the scorer and drafter get clean, comparable input.
const b = $json.body || {};

const digits = (s) => (s || '').toString().replace(/[^0-9]/g, '');
const phoneRaw = digits(b.phone);
const phone = phoneRaw.length === 10 ? phoneRaw : (phoneRaw.length === 11 && phoneRaw.startsWith('1') ? phoneRaw.slice(1) : phoneRaw);
const phoneValid = phone.length === 10;

const name = (b.name || '').trim();
const firstName = name.split(' ')[0] || 'there';
const email = (b.email || '').trim().toLowerCase();
const emailValid = /.+@.+\..+/.test(email);

// Consent: only TRUE if the source explicitly captured it. Default to FALSE.
const smsConsent = b.sms_consent === true || b.sms_consent === 'true';
const emailConsent = b.email_consent === true || b.email_consent === 'true';

// What's missing — surfaced to the agent and used by the scorer.
const missing = [];
if (!phoneValid) missing.push('valid phone');
if (!emailValid) missing.push('valid email');
if (!b.budget) missing.push('budget');
if (!b.timeline) missing.push('timeline');

return [{ json: {
  name, firstName, phone, phoneValid, email, emailValid,
  smsConsent, emailConsent,
  source: b.source || 'unknown',
  property_or_search: b.property_or_search || b.inquiry_message || 'general inquiry',
  inquiry_message: b.inquiry_message || '',
  budget: b.budget || '',
  timeline: b.timeline || '',
  financing_note: b.financing_note || '',
  missing_info_pre: missing
} }];

