// ---- THE SEND-DECISION GATE: this node decides, not the LLM ----
// Auto-send the first touch ONLY IF all three hold:
//   1) consent captured for a channel, AND
//   2) score is a clean standard lead (hot/warm, not cold), AND
//   3) NOT flagged high-value (luxury) and NOT too ambiguous to touch.
// Anything else -> draft anyway, but route to a human for one-tap approval.

const e = $('Enrich + Normalize Lead').item.json;

// Parse the scorer output defensively (OpenAI node shape varies by version).
let s = { intent:'unknown', price_band:'unknown', timeline:'unknown', financing:'unknown', source_quality:'low', score:'cold', missing_info:[], reason:'' };
try {
  const c = $json;
  const txt = c.message?.content ?? c.content ?? c.text ?? JSON.stringify(c);
  s = typeof txt === 'string' ? JSON.parse(txt) : txt;
} catch (err) { /* fail safe: treat as cold -> human */ }

const hasSmsPath = e.smsConsent && e.phoneValid;
const hasEmailPath = e.emailConsent && e.emailValid;
const hasConsentChannel = hasSmsPath || hasEmailPath;

const isHighValue = s.price_band === 'luxury';
const isColdOrSpam = s.score === 'cold' || s.source_quality === 'low';
const tooAmbiguous = s.intent === 'unknown' || (e.missing_info_pre || []).includes('valid phone') && !hasEmailPath;

// Reasons the system will NOT auto-send (each maps to a real risk).
const holdReasons = [];
if (!hasConsentChannel) holdReasons.push('no_consent');          // TCPA boundary — legal, not tunable
if (isHighValue)        holdReasons.push('high_value');          // luxury lead deserves a human first
if (isColdOrSpam)       holdReasons.push('cold_or_low_quality'); // don't spend a fast touch on spam
if (tooAmbiguous)       holdReasons.push('too_ambiguous');       // can't read it -> don't fire blind

const decision = holdReasons.length === 0 ? 'auto_send' : 'human_approval';

// Which channel would we send on if auto (SMS preferred for speed, else email).
const channel = hasSmsPath ? 'sms' : (hasEmailPath ? 'email' : 'none');

// A sensible next step for the drafter.
const nextStep = s.intent === 'seller' ? 'offer a quick market value chat'
               : s.timeline === 'now' || s.timeline === '0_3_months' ? 'book a showing'
               : 'confirm what they are looking for';

return [{ json: {
  ...e,
  score: s.score, intent: s.intent, price_band: s.price_band,
  timeline_scored: s.timeline, financing: s.financing,
  source_quality: s.source_quality, scorer_reason: s.reason,
  missing_info: [...new Set([...(e.missing_info_pre||[]), ...(s.missing_info||[])])],
  hasSmsPath, hasEmailPath, channel,
  decision, holdReasons, holdReasonText: holdReasons.join(', ') || 'none',
  nextStep
} }];

