// ---- SAFETY DOUBLE-CHECK on the draft (belt and suspenders) ----
// The drafter is instructed to include an opt-out and avoid price commitments,
// but we do NOT rely on the prompt alone for the SMS opt-out — verify in code.
const g = $('Send-Decision Gate').item.json;

let d = { sms: '', email: { subject: '', body: '' } };
try {
  const c = $json;
  const txt = c.message?.content ?? c.content ?? c.text ?? JSON.stringify(c);
  d = typeof txt === 'string' ? JSON.parse(txt) : txt;
} catch (e) { /* leave empty; will route to human */ }

let sms = (d.sms || '').trim();
// Enforce opt-out on any SMS regardless of what the model returned.
if (sms && !/stop/i.test(sms)) sms = sms.replace(/\s*$/, '') + ' Reply STOP to opt out.';

const draftValid = sms.length > 0 && (d.email?.body || '').length > 0;

return [{ json: { ...g, draft_sms: sms, draft_email_subject: d.email?.subject || '', draft_email_body: d.email?.body || '', draftValid } }];

